import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import '../css/CheckoutPage.css';

const CheckoutPage = () => {
  const navigate = useNavigate();

  // Lấy các dữ liệu và hàm từ Context 
  const {
    cart,
    clearCart,
    cartTotal,
    cartCount,
  } = useCart();

  const MAX_QTY = 15;
  const [form, setForm] = useState({
    name: '',
    phone: '',
    address: '',
  });

  const [message, setMessage] = useState({
    text: '',
    type: '',
  });

  const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value,
    });
  };

  const showMessage = (text, type) => {
    setMessage({ text, type });

    setTimeout(() => {
      setMessage({
        text: '',
        type: '',
      });
    }, 3000);
  };

  const handleCheckout = async () => {
    // 1. Kiểm tra giỏ hàng trống
    if (!cart || cart.length === 0) {
      showMessage('Giỏ hàng của bạn đang trống!', 'error');
      return;
    }

    // 2. Kiểm tra thông tin form người nhận
    if (!form.name.trim() || !form.phone.trim() || !form.address.trim()) {
      showMessage('Vui lòng nhập đầy đủ thông tin giao hàng!', 'error');
      return;
    }

    // 3. Kiểm tra giới hạn số lượng sản phẩm
    if (cartCount > MAX_QTY) {
      showMessage(`Không thể thanh toán quá ${MAX_QTY} sản phẩm!`, 'error');
      return;
    }

    // 4. Gom cấu trúc dữ liệu đơn hàng 
    const orderData = {
      customerName: form.name,
      customerPhone: form.phone,
      shippingAddress: form.address,
      totalPrice: cartTotal,
      items: cart.map((item) => ({
        productId: item.id,
        quantity: item.quantity || item.qty || 1, 
        price: item.price,
      })),
    };

    try {
      // 5. Gửi dữ liệu bằng phương thức POST sang Spring Boot
      const response = await fetch("http://localhost:8080/api/orders", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(orderData),
      });

      if (response.ok) {
        // Xóa giỏ hàng local sau khi gọi API tạo đơn thành công
        clearCart(); 

        showMessage('🎉 Đặt hàng và thanh toán thành công!', 'success');

        setTimeout(() => {
          navigate('/');
        }, 2500);
      } else {
        showMessage('❌ Có lỗi xảy ra từ server khi xử lý đơn hàng!', 'error');
      }
    } catch (error) {
      showMessage('❌ Không thể kết nối đến server backend! Hãy bật Spring Boot.', 'error');
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 py-12 px-4">
      <div className="max-w-7xl mx-auto grid lg:grid-cols-2 gap-8">
        
        <div className="bg-white rounded-[32px] shadow-xl border border-gray-100 p-8 md:p-10">
          
          <div className="mb-8">
            <span className="inline-block px-4 py-2 rounded-full bg-green-100 text-green-700 text-sm font-semibold">
              CHECKOUT
            </span>
            <h1 className="text-4xl font-bold text-gray-800 mt-5">
              Thanh toán đơn hàng
            </h1>
            <p className="text-gray-500 mt-3">
              Vui lòng điền đầy đủ thông tin nhận hàng
            </p>
          </div>

          {message.text && (
            <div className={`mb-6 rounded-2xl px-5 py-4 text-sm font-medium border transition-all ${
              message.type === 'success'
                ? 'bg-green-50 text-green-700 border-green-100'
                : 'bg-red-50 text-red-600 border-red-100'
            }`}>
              {message.text}
            </div>
          )}

          <div className="space-y-5">
     
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">
                Họ và tên
              </label>
              <input
                type="text"
                name="name"
                placeholder="Nhập họ tên..."
                value={form.name}
                onChange={handleChange}
                className="w-full px-5 py-4 rounded-2xl border border-gray-200 bg-gray-50 outline-none focus:border-green-500 focus:ring-4 focus:ring-green-100 transition-all duration-200"
              />
            </div>

            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">
                Số điện thoại
              </label>
              <input
                type="text"
                name="phone"
                placeholder="Nhập số điện thoại..."
                value={form.phone}
                onChange={handleChange}
                className="w-full px-5 py-4 rounded-2xl border border-gray-200 bg-gray-50 outline-none focus:border-green-500 focus:ring-4 focus:ring-green-100 transition-all duration-200"
              />
            </div>

            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">
                Địa chỉ giao hàng
              </label>
              <textarea
                name="address"
                rows="4"
                placeholder="Nhập địa chỉ nhận hàng chi tiết..."
                value={form.address}
                onChange={handleChange}
                className="w-full px-5 py-4 rounded-2xl border border-gray-200 bg-gray-50 outline-none resize-none focus:border-green-500 focus:ring-4 focus:ring-green-100 transition-all duration-200"
              />
            </div>
          </div>

          <div className="flex flex-col sm:flex-row gap-4 mt-8">
            <button
              onClick={handleCheckout}
              className="flex-1 py-4 rounded-2xl bg-green-600 hover:bg-green-700 text-white font-semibold transition-all duration-300 shadow-lg hover:shadow-xl transform active:scale-[0.98]"
            >
              🧾 Xác nhận thanh toán
            </button>

            <button
              onClick={() => navigate(-1)}
              className="flex-1 py-4 rounded-2xl border border-gray-200 bg-white hover:bg-gray-50 text-gray-700 font-semibold transition-all duration-300"
            >
              ⬅ Quay về
            </button>
          </div>
        </div>

        <div className="bg-white rounded-[32px] shadow-xl border border-gray-100 p-8 md:p-10 h-fit lg:sticky lg:top-6">
          
          <div className="mb-8">
            <h2 className="text-3xl font-bold text-gray-800">
              🛒 Đơn hàng của bạn
            </h2>
            <p className="text-gray-500 mt-2">
              {cartCount} sản phẩm trong giỏ hàng
            </p>
          </div>

          {!cart || cart.length === 0 ? (
            <div className="bg-gray-50 border border-gray-100 rounded-3xl py-16 text-center">
              <h3 className="text-xl font-semibold text-gray-700">Chưa có sản phẩm</h3>
              <p className="text-gray-400 mt-2">Hãy thêm sản phẩm vào giỏ hàng</p>
            </div>
          ) : (
            <>

              <div className="space-y-5 max-h-[450px] overflow-y-auto pr-1">
                {cart.map((item) => (
                  <div
                    key={item.id}
                    className="flex gap-4 p-4 rounded-3xl bg-gray-50 border border-gray-100 items-center"
                  >
                    
                    <div className="w-24 h-24 rounded-2xl overflow-hidden bg-gray-100 flex-shrink-0 border border-gray-200">
                      <img
                        src={item.image}
                        alt={item.name}
                        className="w-full h-full object-cover"
                      />
                    </div>

                    {/* THÔNG TIN SẢN PHẨM */}
                    <div className="flex-1 min-w-0">
                      <h3 className="text-lg font-semibold text-gray-800 truncate">
                        {item.name}
                      </h3>
                      <p className="text-gray-500 mt-1 text-sm">
                        Số lượng: {item.quantity || item.qty || 1}
                      </p>
                      <p className="text-green-600 font-bold text-xl mt-2">
                        {(item.price * (item.quantity || item.qty || 1)).toLocaleString('vi-VN')}đ
                      </p>
                    </div>
                  </div>
                ))}
              </div>

              {/* TỔNG KẾT HÓA ĐƠN */}
              <div className="mt-8 pt-6 border-t border-dashed border-gray-300">
                <div className="flex items-center justify-between">
                  <span className="text-lg font-semibold text-gray-700">
                    Tổng thanh toán
                  </span>
                  <span className="text-3xl font-bold text-green-600">
                    {cartTotal.toLocaleString('vi-VN')}đ
                  </span>
                </div>
                <p className="text-sm text-gray-400 mt-3">
                  Đã bao gồm toàn bộ chi phí vận chuyển
                </p>
              </div>
            </>
          )}
        </div>

      </div>
    </div>
  );
};

export default CheckoutPage;
